/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `t_insertQueueName` BEFORE INSERT ON `matches` FOR EACH ROW BEGIN
    IF NEW.QueueID = 400 THEN
        SET NEW.queueName = "Normal SR";
    ELSEIF NEW.QueueID = 420 THEN
        SET NEW.queueName = "Ranked SR";
    ELSE
        SET NEW.queueName = "Unknown";
    END IF;
END */;;
